<?php
 declare(strict_types=1); namespace tapmeppe\composer\helpers; use WP_REST_Request; use WP_REST_Response; abstract class Route { protected string $route; function __construct() { foreach (['delete', 'get', 'post', 'put'] as $method) { $settings = ['methods' => strtoupper($method), 'callback' => [$this, $method],]; if (method_exists($this, $permission = 'can' . ucfirst($method))) $settings['permission_callback'] = [$this, $permission]; register_rest_route('governance', "/$this->route/", $settings); } } function delete(WP_REST_Request $request): WP_REST_Response { return new WP_REST_Response(['Not implemented'], 501); } function get(WP_REST_Request $request): WP_REST_Response { return new WP_REST_Response(['Not implemented'], 501); } function post(WP_REST_Request $request): WP_REST_Response { return new WP_REST_Response(['Not implemented'], 501); } function put(WP_REST_Request $request): WP_REST_Response { return new WP_REST_Response(['Not implemented'], 501); } } 